#include <algorithm>
#include <iostream>
#include <vector>

int main()
{
    int n{};
    std::cin >> n;

    std::vector<int> v(n);
    for (int i{ 0 }; i < n; ++i)
        std::cin >> v[i];

    auto evens{ std::count_if(v.begin(), v.end(),
        [](int x) { return x % 2 == 0; }) };
    auto negatives{ std::count_if(v.begin(), v.end(),
        [](int x) { return x < 0; }) };

    std::cout << "Even: " << evens << '\n';
    std::cout << "Negative: " << negatives << '\n';

    return 0;
}

